<?php require __DIR__.'/includes/bootstrap.php';
if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();$email=strtolower(trim($_POST['email']??''));$s=db()->prepare("SELECT id,email FROM users WHERE email=? AND status='active'");$s->execute([$email]);if($u=$s->fetch()){$token=bin2hex(random_bytes(32));db()->prepare('INSERT INTO password_resets(user_id,token_hash,expires_at) VALUES(?,?,DATE_ADD(NOW(),INTERVAL 1 HOUR))')->execute([$u['id'],hash('sha256',$token)]);smtp_send($email,'Reset your Geek Nation Multiverse password','<p><a href="'.e(base_url('reset-password.php?token='.$token)).'">Reset your password</a></p><p>This link expires in one hour.</p>');}flash('success','If that address is registered, a reset link has been sent.');redirect('login.php');}
app_header('Forgot Password');?><section class="auth-page"><form class="auth-card" method="post"><?=csrf_field()?><h1>Reset password</h1><label>Email<input type="email" name="email" required></label><button class="button primary">Send Reset Link</button></form></section><?php app_footer();
